{
  "name": "@splitzy/shared-zero",
  "version": "0.0.0",
  "private": true,
  "type": "module",
  "exports": {
    ".": {
      "types": "./dist/index.d.ts",
      "default": "./dist/index.js"
    },
    "./schema": {
      "types": "./dist/schema.d.ts",
      "default": "./dist/schema.js"
    },
    "./mutators": {
      "types": "./dist/mutators.d.ts",
      "default": "./dist/mutators.js"
    }
  },
  "files": [
    "dist"
  ],
  "scripts": {
    "build": "tsc",
    "dev": "tsc -w",
    "type-check": "tsc --noEmit",
    "format": "prettier --check .",
    "format:fix": "prettier --write --ignore-unknown .",
    "check": "pnpm run format && pnpm run type-check"
  },
  "dependencies": {
    "@rocicorp/zero": "^0.25.12",
    "zod": "^4.2.1"
  },
  "devDependencies": {
    "@types/node": "^20.11.17",
    "prettier": "^3.8.1",
    "typescript": "^5.8.3"
  }
}

import { defineQueries, defineQuery } from '@rocicorp/zero';
import { zql } from '@splitzy/shared-zero';
import { z } from 'zod';

export const queries = defineQueries({
  users: {
    receipts: {
      byAuthUserId: defineQuery(z.object({}), ({ ctx }) =>
        zql.users
          .where('auth_user_id', ctx.userID ?? '')
          .related('receipts', (q) =>
            q.where('deleted_at', 'IS', null).orderBy('created_at', 'desc')
          )
          .one()
      ),
    },
  },
  receipt: {
    byId: defineQuery(z.object({ id: z.number() }), ({ args: { id } }) =>
      zql.user_receipts
        .where('id', id)
        .where('deleted_at', 'IS', null)
        .related('line_items', (q) =>
          q
            .where('deleted_at', 'IS', null)
            .related('assignments', (q) =>
              q
                .where('deleted_at', 'IS', null)
                .related('receipt_user', (q) =>
                  q.where('deleted_at', 'IS', null).related('user')
                )
            )
        )
        .related('user')
        .one()
    ),
  },
});

